    34→export const initialState: RescueReducerProps = {
    35→  isLoading: false,
    36→  isError: false,
    37→  status: undefined,
    38→};
    39→
    40→export const rescueReducer = createReducer(initialState, {
    41→  [RescueTypes.REQUEST](state: State) {
    42→    return {
    43→      ...state,
    44→      isLoading: true,
    45→      isError: false,
    46→    };
    47→  },
    48→  [RescueTypes.SUCCESS](state: State, { status }: { status: ResgateResponse['status'] }) {
    49→    return {
    50→      ...state,
    51→      status,
    52→      isLoading: false,
    53→      isError: false,
    54→    };
    55→  },
    56→  [RescueTypes.FAILED](state: State, { status }: { status?: ResgateResponse['status'] }) {
    57→    return {
    58→      ...state,
    59→      status,
    60→      isLoading: false,
    61→      isError: true,
    62→    };
    63→  },
    64→  [RescueTypes.CLEAR](): State {
    65→    return initialState;
    66→  },
    67→});
