    81→  rescueRequest: (data: {
    82→    payload?: RescuePayload;
    83→    onSuccess?: (status: ResgateResponse['status']) => void;
    84→    onFailed?: (status?: ResgateResponse['status']) => void;
    85→  }) => ({
    86→    type: RescueTypes.REQUEST,
