    10→export function* getMarketplace(payload: { data: Record<string, string> }) {
    11→  try {
    12→    const urlParams = new URLSearchParams(payload.data);
    13→    const response: AxiosResponse<GetMarketplaceResponse> = yield call(
    14→      api.get,
    15→      `/marketplace/v1/vertem/getToken?${urlParams.toString()}`,
    16→    );
    17→    if (response.data.status.codigoRetorno === 0) {
    18→      yield put(getMarketplaceActions.successGetMarketplace(response.data));
    19→    } else {
    20→      yield put(getMarketplaceActions.failedGetMarketplace());
    21→    }
    22→  } catch {
    23→    yield put(getMarketplaceActions.failedGetMarketplace());
    24→  }
    25→}
