   423→+import type moment from 'moment';
   424→+import type { MyOrdersDetailProps, TransactionType } from './Models';
   425→+
   426→+export type TransactionGainType = 'CARD' | 'TAG' | 'CASHBACK';
   427→+
   428→+export const getTransactionGainType = (
   429→+  transaction: MyOrdersDetailProps['transaction'],
   430→+): TransactionGainType => {
   431→+  if (!transaction) return 'CARD';
   432→+
   433→+  const provider = transaction.details?.provider?.toLowerCase() || '';
   434→+
   435→+  if (provider.includes('cashback')) {
   436→+    return 'CASHBACK';
   437→+  }
   438→+
   439→+  const icon = transaction.icon?.toLowerCase() || '';
   440→+  const description = transaction.description?.toLowerCase() || '';
   441→+
   442→+  const tagIndicators = [
   443→+    'tag',
   444→+    'pedágio',
   445→+    'pedagio',
   446→+    'estacionamento',
   447→+    'abastecimento',
   448→+    'abastece',
   449→+    'drive',
   450→+    'lava',
   451→+    'rápido',
   452→+  ];
   453→+
   454→+  const isTag = tagIndicators.some(
   455→+    indicator =>
   456→+      icon.includes(indicator) ||
   457→+      description.includes(indicator) ||
   458→+      provider.includes(indicator),
   459→+  );
   460→+
   461→+  return isTag ? 'TAG' : 'CARD';
   462→+};
   463→+
   464→+export const getFormattedPointsValue = (
   465→+  amount: number,
   466→+  type: TransactionType,
   467→+): string => {
   468→+  const prefix = type === 'CREDIT' || type === 'REFUNDED' ? '+ ' : '- ';
   469→+  const label = Math.abs(amount) === 1 ? 'ponto' : 'pontos';
   470→+  return `${prefix}${Math.abs(amount).toLocaleString('pt-BR')} ${label}`;
   471→+};
   472→+
   473→+export const getFormattedHighlightText = (
   474→+  date: string,
   475→+  _gainType: TransactionGainType,
   476→+  momentInstance: typeof moment,
   477→+): string => {
   478→+  const transactionDate = momentInstance(date);
   479→+  const day = transactionDate.format('DD');
   480→+  const month = transactionDate.format('MMM').toLowerCase();
   481→+  const year = transactionDate.format('YYYY');
   482→+  const time = transactionDate.format('HH:mm');
   483→+
   484→+  return `Pedido feito em ${day} ${month} ${year} às ${time}`;
   485→+};
   486→+
   487→+export const getFormattedPointsValueForMarketplace = (
   488→+  valuePoints: number,
   489→+): string => {
   490→+  const absValue = Math.abs(valuePoints);
