   495→+export const getPaymentTypeLabel = (paymentType: string): string => {
   496→+  const labels: Record<string, string> = {
   497→+    POINTS: 'Pontos',
   498→+    CARD: 'Cartão',
   499→+    PIX: 'PIX',
