   503→+
   504→+export const getMarketplaceTitle = (
   505→+  transaction: MyOrdersDetailProps['transaction'],
   506→+): string | null => {
   507→+  if (!transaction?.marketplace?.orders) return null;
   508→+
   509→+  const allItems: Array<{ name: string }> = [];
   510→+  transaction.marketplace.orders.forEach(order => {
   511→+    if (order.items) {
   512→+      allItems.push(...order.items);
   513→+    }
   514→+  });
   515→+
   516→+  if (allItems.length === 0) return null;
   517→+  if (allItems.length === 1) return allItems[0].name;
   518→+
   519→+  const firstItemName = allItems[0].name;
   520→+  const secondItemFirstWord = allItems[1].name.split(' ')[0];
   521→+
   522→+  if (allItems.length === 2) {
   523→+    return `${firstItemName} e ${secondItemFirstWord}`;
   524→+  }
   525→+
   526→+  const remainingCount = allItems.length - 2;
   527→+  return `${firstItemName}, ${secondItemFirstWord} e outros ${remainingCount}`;
   528→+};
