   530→+export const getCleanedImageUrl = (
   531→+  url: string | undefined,
   532→+): string | undefined => {
   533→+  if (!url) return undefined;
   534→+
   535→+  let cleanedUrl = url.trim();
   536→+
   537→+  if (cleanedUrl.startsWith('imageUrl:')) {
   538→+    cleanedUrl = cleanedUrl.replace(/^imageUrl:/i, '');
   539→+  }
   540→+
   541→+  if (cleanedUrl.startsWith('http://') || cleanedUrl.startsWith('https://')) {
   542→+    return cleanedUrl;
   543→+  }
   544→+
   545→+  return undefined;
   546→+};
