  1419→+
  1420→+function getTransactionFromOrderDetail(
  1421→+  dto: OrderDetailDataDto,
  1422→+): PointsTransaction {
  1423→+  const items = dto.items || [];
  1424→+  const benefits = dto.benefits || [];
  1425→+
  1426→+  const totalValue = items.reduce(
  1427→+    (sum, item) => sum + item.unitaryValue * item.quantity,
  1428→+    0,
  1429→+  );
  1430→+
  1431→+  const fields: Array<{
  1432→+    label: string;
  1433→+    value: string;
  1434→+  }> = [];
  1435→+
  1436→+  if (items.length > 0) {
  1437→+    items.forEach((item, index) => {
  1438→+      fields.push({
  1439→+        label: `Item ${index + 1}`,
  1440→+        value: `${item.description} - ${item.quantity}x R$ ${item.unitaryValue.toFixed(2)}`,
  1441→+      });
  1442→+    });
  1443→+  }
  1444→+
  1445→+  if (benefits.length > 0) {
  1446→+    benefits.forEach((benefit, index) => {
  1447→+      fields.push({
  1448→+        label: `Benefício ${index + 1}`,
  1449→+        value: `${benefit.description} - R$ ${Math.abs(benefit.value).toFixed(2)}`,
  1450→+      });
  1451→+    });
  1452→+  }
  1453→+
  1454→+  return {
  1455→+    id: dto.id,
  1456→+    date: dto.date,
  1457→+    description: dto.description,
  1458→+    type: 'RESCUE',
  1459→+    amount: dto.amount,
  1460→+    currencyValue: totalValue > 0 ? totalValue : Math.abs(dto.amount),
  1461→+    icon: 'icon-cashback',
  1462→+    details: {
  1463→+      provider: 'Cashback',
  1464→+      extraInfo: '',
  1465→+      fields,
  1466→+    },
  1467→+    status: '',
  1468→+    marketplace: dto.marketplace,
  1469→+  };
  1470→+}
  1471→+
  1472→+export function getOrderDetailFromResponse(
  1473→+  response: Awaited<ReturnType<typeof getOrderDetailApi>>,
  1474→+): PointsTransaction | null {
  1475→+  const apiResponse = response?.data;
  1476→+
  1477→+  if (!apiResponse) {
  1478→+    return null;
  1479→+  }
  1480→+
  1481→+  const status = apiResponse.status;
  1482→+  const returnCode = status?.returnCode;
  1483→+
  1484→+  if (returnCode !== 200 && returnCode !== 0) {
  1485→+    return null;
  1486→+  }
  1487→+
  1488→+  const orderDetailData = apiResponse.data;
  1489→+
  1490→+  if (!orderDetailData) {
  1491→+    return null;
  1492→+  }
  1493→+
  1494→+  return getTransactionFromOrderDetail(orderDetailData);
  1495→+}
