  1514→+import { eventServerResponse } from '~/constants/functions';
  1515→+import { useRootStore } from '~/store';
  1516→+import {
  1517→+  getOrderDetailApi,
  1518→+  type OrderDetailRequestDto,
  1519→+} from '../api/orderDetail.api';
  1520→+import { OrderDetailStatus } from '../models/orderDetail.model';
  1521→+import { getOrderDetailFromResponse } from '../repository/orderDetail.repository';
  1522→+import { getParticipantIdFromToken } from '../utils';
  1523→+
  1524→+interface GetOrderDetailPayload {
  1525→+  transactionId: string;
  1526→+  participantId?: string;
  1527→+}
  1528→+
  1529→+function handleOrderDetailSuccess(
  1530→+  orderDetail: ReturnType<typeof getOrderDetailFromResponse>,
  1531→+  transactionId: string,
  1532→+): void {
  1533→+  const { orderDetailActions } = useRootStore.getState();
  1534→+
  1535→+  if (orderDetail) {
  1536→+    orderDetailActions.setOrderDetail(orderDetail, transactionId);
  1537→+    eventServerResponse('ORDER_DETAIL_SUCCESS' as never);
  1538→+  } else {
  1539→+    handleOrderDetailError();
  1540→+  }
  1541→+}
  1542→+
  1543→+function handleOrderDetailError(): void {
  1544→+  const { orderDetailActions } = useRootStore.getState();
  1545→+  orderDetailActions.setOrderDetailStatus(OrderDetailStatus.ERROR);
  1546→+  eventServerResponse('ORDER_DETAIL_ERROR' as never);
  1547→+}
  1548→+
  1549→+export async function getOrderDetail(
  1550→+  payload: GetOrderDetailPayload,
  1551→+): Promise<void> {
  1552→+  const { orderDetailActions, orderDetail } = useRootStore.getState();
  1553→+
  1554→+  const isDifferentTransaction =
  1555→+    orderDetail.transactionId !== payload.transactionId;
  1556→+  const isAlreadyLoading = orderDetail.status === OrderDetailStatus.LOADING;
  1557→+
  1558→+  if (isAlreadyLoading && !isDifferentTransaction) {
  1559→+    return;
  1560→+  }
  1561→+
  1562→+  if (isDifferentTransaction) {
  1563→+    orderDetailActions.reset();
  1564→+  }
  1565→+
  1566→+  orderDetailActions.setOrderDetailStatus(OrderDetailStatus.LOADING);
  1567→+
  1568→+  try {
  1569→+    const participantId =
  1570→+      payload?.participantId ?? (await getParticipantIdFromToken());
  1571→+
  1572→+    if (!participantId) {
  1573→+      handleOrderDetailError();
  1574→+      return;
  1575→+    }
  1576→+
  1577→+    const requestPayload: OrderDetailRequestDto = {
  1578→+      transactionId: payload.transactionId,
  1579→+      participantId,
  1580→+    };
  1581→+
  1582→+    const response = await getOrderDetailApi(requestPayload);
  1583→+    const orderDetailData = getOrderDetailFromResponse(response);
  1584→+
  1585→+    if (orderDetailData) {
  1586→+      handleOrderDetailSuccess(orderDetailData, payload.transactionId);
  1587→+      return;
  1588→+    }
  1589→+
  1590→+    handleOrderDetailError();
  1591→+  } catch {
  1592→+    handleOrderDetailError();
  1593→+  }
  1594→+}
